package com.chrisb97.warehouse.controller;
import com.chrisb97.warehouse.config.AppContext;import com.chrisb97.warehouse.model.*;import com.chrisb97.warehouse.util.DateTimeUtil;import javafx.beans.property.SimpleStringProperty;import javafx.collections.FXCollections;import javafx.fxml.FXML;import javafx.scene.control.*;
public class MovementsController{@FXML private ComboBox<Product> productFilter;@FXML private ComboBox<MovementType> typeFilter;@FXML private DatePicker fromDate,toDate;@FXML private TableView<StockMovement> table;@FXML private TableColumn<StockMovement,String> dateColumn,skuColumn,productColumn,typeColumn,quantityColumn,previousColumn,newColumn,locationColumn,reasonColumn,referenceColumn;
@FXML public void initialize(){productFilter.setItems(FXCollections.observableArrayList(AppContext.getInstance().products().activeProducts()));typeFilter.setItems(FXCollections.observableArrayList(MovementType.values()));dateColumn.setCellValueFactory(d->new SimpleStringProperty(DateTimeUtil.format(d.getValue().getCreatedAt())));skuColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().getProductSku()));productColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().getProductName()));typeColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().getMovementType().name()));quantityColumn.setCellValueFactory(d->new SimpleStringProperty(String.valueOf(d.getValue().getQuantity())));previousColumn.setCellValueFactory(d->new SimpleStringProperty(String.valueOf(d.getValue().getPreviousQuantity())));newColumn.setCellValueFactory(d->new SimpleStringProperty(String.valueOf(d.getValue().getNewQuantity())));locationColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().getLocationCode()));reasonColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().getReason()));referenceColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().getReference()));refresh();}
@FXML private void refresh(){Long id=productFilter.getValue()==null?null:productFilter.getValue().getId();table.setItems(FXCollections.observableArrayList(AppContext.getInstance().movements().search(id,typeFilter.getValue(),fromDate.getValue(),toDate.getValue())));}@FXML private void clearFilters(){productFilter.setValue(null);typeFilter.setValue(null);fromDate.setValue(null);toDate.setValue(null);refresh();}}
